module RefModule (
    input J,
    input K,
    input clk,
    input reset,
    output reg Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) 
            Q <= 0;
        else if (J && ~K) 
            Q <= 1;
        else if (~J && K) 
            Q <= 0;
        else if (J && K) 
            Q <= ~Q; // Toggle
    end
endmodule
